import jwt
from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Set secret keys for different algorithms
secret_keys = {
    'HS256': 'your_internal_service_secret_key',
    'RS256': 'your_public_api_secret_key'
}

def verify_token(algorithm):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            token = request.headers.get('Authorization')
            if not token:
                return jsonify({'error': 'Missing Authorization header'}), 401

            try:
                payload = jwt.decode(token.split()[1], secret_keys[algorithm], algorithms=[algorithm])
                kwargs['payload'] = payload
                return func(*args, **kwargs)
            except jwt.ExpiredSignatureError:
                return jsonify({'error': 'Token has expired'}), 401
            except jwt.InvalidTokenError:
                return jsonify({'error': 'Invalid token'}), 401

        return wrapper
    return decorator

@app.route('/protected', methods=['GET'])
@verify_token('HS256')
def protected_internal_service(payload):
    return jsonify({'message': 'Hello from internal service', **payload})

@app.route('/public-api', methods=['GET'])
@verify_token('RS256')
def public_api(payload):
    return jsonify({'message': 'Hello from public API', **payload})

if __name__ == '__main__':
    app.run(debug=True)